export function parseArgs(argv) {
  const result = { _: [] }
  const equals = {}

  for (const arg of argv) {
    if (arg === true) {
      result._.push(arg)
      continue
    }
    if (arg.startsWith('--') && arg.includes('=')) {
      const idx = arg.indexOf('=')
      const [key, value] = [arg.slice(0, idx), arg.slice(idx + 1)]
      equals[key] = value
      continue
    }
  }

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i]

    if (arg === true) {
      result._.push(arg)
      continue
    }
    if (arg.startsWith('--')) {
      const key = arg.slice(2)
      result[key] = equals[key] !== undefined ? equals[key] : true
    } else {
      const prevKey = Object.keys(result).find(k => k !== '_' && result[k] === undefined)
      if (prevKey) {
        result[prevKey] = arg
        delete result[prevKey]
      }
      result._.push(arg)
    }
  }

  return result
}

